import React, { createContext, useState, useRef, useContext, useEffect } from 'react';
import axios from 'axios';

const MusicContext = createContext();

export const MusicProvider = ({ children }) => {
  const [songs, setSongs] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentSong, setCurrentSong] = useState(null);
  const [favorites, setFavorites] = useState([]);
  
  // Bổ sung State thời gian
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  
  const audioRef = useRef(null);
  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  // Lấy danh sách yêu thích khi load trang
  useEffect(() => {
    const fetchFavorites = async () => {
      if (loggedInUser) {
        try {
          const userId = loggedInUser._id || loggedInUser.id;
          const res = await axios.get(`http://localhost:5000/api/auth/${userId}/favorites`);
          setFavorites(res.data.map(song => song._id));
        } catch (err) { console.error("Lỗi tải favorites:", err); }
      }
    };
    fetchFavorites();
  }, []);

  // Tự động phát nhạc
  useEffect(() => {
    if (currentSong && isPlaying && audioRef.current) {
      audioRef.current.play().catch(() => setIsPlaying(false));
    }
  }, [currentSong]);

  const playMusic = (songList, index) => {
    setSongs(songList);
    setCurrentIndex(index);
    setCurrentSong(songList[index]);
    setIsPlaying(true);
  };

  const togglePlay = () => {
    if (!currentSong) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const handleNext = () => {
    if (songs.length === 0) return;
    const nextIndex = (currentIndex + 1) % songs.length;
    setCurrentIndex(nextIndex);
    setCurrentSong(songs[nextIndex]);
    setIsPlaying(true);
  };

  const handlePrev = () => {
    if (songs.length === 0) return;
    const prevIndex = (currentIndex - 1 + songs.length) % songs.length;
    setCurrentIndex(prevIndex);
    setCurrentSong(songs[prevIndex]);
    setIsPlaying(true);
  };

  // CẬP NHẬT TRẠNG THÁI LIKE
  const toggleLike = async (songId) => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập!");
    try {
      const userId = loggedInUser._id || loggedInUser.id;
      const res = await axios.post('http://localhost:5000/api/auth/toggle-favorite', { userId, songId });
      // Quan trọng: Cập nhật lại state favorites bằng dữ liệu mới từ Backend
      setFavorites(res.data.favorites); 
    } catch (err) { console.error(err); }
  };

  // Xử lý khi bài hát đang chạy để cập nhật thanh tiến trình
  const onTimeUpdate = () => {
    if (audioRef.current) {
      setCurrentTime(audioRef.current.currentTime);
    }
  };

  const onLoadedMetadata = () => {
    if (audioRef.current) {
      setDuration(audioRef.current.duration);
    }
  };

  // Hàm để người dùng kéo thanh trượt (tua nhạc)
  const seekTo = (time) => {
    if (audioRef.current) {
      audioRef.current.currentTime = time;
      setCurrentTime(time);
    }
  };

  return (
    <MusicContext.Provider value={{ 
      songs, currentSong, isPlaying, setIsPlaying, currentIndex, 
      audioRef, playMusic, togglePlay, handleNext, handlePrev,
      favorites, toggleLike,
      currentTime, duration, seekTo // Export thêm thông tin thời gian
    }}>
      {children}
      {currentSong && (
        <audio
          ref={audioRef}
          src={`http://localhost:5000${currentSong.musicUrl}`}
          onTimeUpdate={onTimeUpdate}
          onLoadedMetadata={onLoadedMetadata}
          onEnded={handleNext}
        />
      )}
    </MusicContext.Provider>
  );
};

export const useMusic = () => useContext(MusicContext);
